    18→
    19→package org.apache.flink.streaming.api.windowing.assigners;
    20→
    21→import org.apache.flink.annotation.PublicEvolving;
    22→import org.apache.flink.api.common.ExecutionConfig;
    23→import org.apache.flink.api.common.typeutils.TypeSerializer;
    24→import org.apache.flink.streaming.api.windowing.triggers.EventTimeTrigger;
    25→import org.apache.flink.streaming.api.windowing.triggers.Trigger;
    26→import org.apache.flink.streaming.api.windowing.windows.TimeWindow;
    27→
    28→import java.time.LocalTime;
    29→import java.time.ZoneId;
    30→import java.time.ZonedDateTime;
    31→import java.util.Collection;
    32→import java.util.Collections;
    33→
    34→/**
    35→ * A {@link WindowAssigner} that assigns elements to time windows based on trading market sessions.
    36→ * Windows are determined by market open and close times in the specified timezone.
    37→ *
    38→ * <p>For example, to window NYSE trading data into daily sessions (9:30 AM - 4:00 PM ET):
    39→ *
    40→ * <pre>{@code
    41→ * DataStream<TradeEvent> trades = ...;
    42→ * KeyedStream<TradeEvent, String> keyed = trades.keyBy(...);
    43→ * WindowedStream<TradeEvent, String, TimeWindow> windowed =
    44→ *   keyed.window(PricingSessionWindow.forMarket(
    45→ *     "NYSE",
    46→ *     ZoneId.of("America/New_York"),
    47→ *     LocalTime.of(9, 30),
    48→ *     LocalTime.of(16, 0)));
    49→ * }</pre>
    50→ *
    51→ * <p>This implementation handles market sessions that may span date boundaries (e.g., futures
    52→ * markets that trade overnight).
    53→ */
    54→@PublicEvolving
    55→public class PricingSessionWindow extends MergingWindowAssigner<Object, TimeWindow> {
    56→    private static final long serialVersionUID = 1L;
    57→
    58→    private final String marketId;
    59→    private final ZoneId timezone;
    60→    private final LocalTime sessionOpen;
    61→    private final LocalTime sessionClose;
    62→
    63→    protected PricingSessionWindow(
    64→            String marketId, ZoneId timezone, LocalTime sessionOpen, LocalTime sessionClose) {
    65→        if (marketId == null || marketId.isEmpty()) {
    66→            throw new IllegalArgumentException("Market ID must not be null or empty");
    67→        }
    68→        if (timezone == null) {
    69→            throw new IllegalArgumentException("Timezone must not be null");
    70→        }
    71→        if (sessionOpen == null || sessionClose == null) {
    72→            throw new IllegalArgumentException(
    73→                    "Session open and close times must not be null");
    74→        }
    75→
    76→        this.marketId = marketId;
    77→        this.timezone = timezone;
    78→        this.sessionOpen = sessionOpen;
    79→        this.sessionClose = sessionClose;
    80→    }
    81→
    82→    @Override
    83→    public Collection<TimeWindow> assignWindows(
    84→            Object element, long timestamp, WindowAssignerContext context) {
    85→        // Convert the timestamp to the market's timezone
    86→        ZonedDateTime eventTime = ZonedDateTime.ofInstant(
    87→                java.time.Instant.ofEpochMilli(timestamp), timezone);
    88→
    89→        // Get the session window for this timestamp
    90→        TimeWindow window = getSessionWindow(eventTime);
    91→        return Collections.singletonList(window);
    92→    }
    93→
    94→    /**
    95→     * Determines the trading session window for a given timestamp.
    96→     *
    97→     * <p>If the timestamp falls within the session hours, returns a window from that day's open
    98→     * to close. If the timestamp is outside session hours, returns a window for the next session.
    99→     *
   100→     * @param eventTime The event time in the market's timezone
   101→     * @return A TimeWindow representing the trading session
   102→     */
   103→    private TimeWindow getSessionWindow(ZonedDateTime eventTime) {
   104→        LocalTime eventLocalTime = eventTime.toLocalTime();
   105→        java.time.LocalDate eventDate = eventTime.toLocalDate();
   106→
   107→        // Determine if event time is within session hours
   108→        boolean withinSession =
   109→                !eventLocalTime.isBefore(sessionOpen)
   110→                        && eventLocalTime.isBefore(sessionClose);
   111→
   112→        java.time.LocalDate sessionDate;
   113→        if (withinSession) {
   114→            // Event is within the session, use current date
   115→            sessionDate = eventDate;
   116→        } else if (eventLocalTime.isBefore(sessionOpen)) {
   117→            // Event is before session opens, use current date (it's tonight's session)
   118→            sessionDate = eventDate;
   119→        } else {
   120→            // Event is after session closes, belongs to next day's session
   121→            sessionDate = eventDate.plusDays(1);
   122→        }
   123→
   124→        // Create the session window for this date
   125→        ZonedDateTime sessionOpenTime =
   126→                ZonedDateTime.of(sessionDate, sessionOpen, timezone);
   127→        ZonedDateTime sessionCloseTime =
   128→                ZonedDateTime.of(sessionDate, sessionClose, timezone);
   129→
   130→        // Handle overnight sessions (close time before open time)
   131→        if (sessionClose.isBefore(sessionOpen)) {
   132→            // If close time is on the next day
   133→            if (eventLocalTime.isBefore(sessionClose)) {
   134→                // Event is in the early morning part of an overnight session
   135→                sessionOpenTime = sessionOpenTime.minusDays(1);
   136→            }
   137→            sessionCloseTime = sessionCloseTime.plusDays(1);
   138→        }
   139→
   140→        long windowStart = sessionOpenTime.toInstant().toEpochMilli();
   141→        long windowEnd = sessionCloseTime.toInstant().toEpochMilli();
   142→
   143→        return new TimeWindow(windowStart, windowEnd);
   144→    }
   145→
   146→    @Override
   147→    public Trigger<Object, TimeWindow> getDefaultTrigger() {
   148→        return EventTimeTrigger.create();
   149→    }
   150→
   151→    @Override
   152→    public TypeSerializer<TimeWindow> getWindowSerializer(ExecutionConfig executionConfig) {
   153→        return new TimeWindow.Serializer();
   154→    }
   155→
   156→    @Override
   157→    public boolean isEventTime() {
   158→        return true;
   159→    }
   160→
   161→    @Override
   162→    public void mergeWindows(Collection<TimeWindow> windows, MergeCallback<TimeWindow> c) {
   163→        TimeWindow.mergeWindows(windows, c);
   164→    }
   165→
   166→    @Override
   167→    public String toString() {
   168→        return String.format(
   169→                "PricingSessionWindow(%s, %s, %s-%s)",
   170→                marketId, timezone, sessionOpen, sessionClose);
   171→    }
   172→
   173→    /**
   174→     * Creates a new {@code PricingSessionWindow} that assigns elements to windows based on trading
   175→     * session times.
   176→     *
   177→     * @param marketId The market identifier (e.g., "NYSE", "LSE")
   178→     * @param timezone The timezone in which the session times are defined
   179→     * @param sessionOpen The local time when the session opens (e.g., 09:30)
   180→     * @param sessionClose The local time when the session closes (e.g., 16:00)
   181→     * @return A new PricingSessionWindow assigner
   182→     */
   183→    public static PricingSessionWindow forMarket(
   184→            String marketId, ZoneId timezone, LocalTime sessionOpen, LocalTime sessionClose) {
   185→        return new PricingSessionWindow(marketId, timezone, sessionOpen, sessionClose);
   186→    }
   187→
   188→    /**
   189→     * Creates a new {@code PricingSessionWindow} with dynamic market extraction.
   190→     *
   191→     * @param <T> The type of elements
   192→     * @param extractor The extractor to use to extract the market ID from input elements
   193→     * @param timezone The timezone in which the session times are defined
   194→     * @param sessionOpen The local time when the session opens (e.g., 09:30)
   195→     * @param sessionClose The local time when the session closes (e.g., 16:00)
   196→     * @return A new DynamicPricingSessionWindow assigner
   197→     */
   198→    @PublicEvolving
   199→    public static <T> DynamicPricingSessionWindow<T> withDynamicMarket(
   200→            TradingSessionExtractor<T> extractor,
   201→            ZoneId timezone,
   202→            LocalTime sessionOpen,
   203→            LocalTime sessionClose) {
   204→        return new DynamicPricingSessionWindow<>(extractor, timezone, sessionOpen, sessionClose);
   205→    }
   206→}
