package org.apache.flink.streaming.api.windowing.assigners;

import org.apache.flink.annotation.PublicEvolving;
import org.apache.flink.api.common.ExecutionConfig;
import org.apache.flink.api.common.typeutils.TypeSerializer;
import org.apache.flink.streaming.api.windowing.triggers.EventTimeTrigger;
import org.apache.flink.streaming.api.windowing.triggers.Trigger;
import org.apache.flink.streaming.api.windowing.windows.TimeWindow;

import java.time.LocalTime;
import java.time.ZoneId;
import java.time.ZonedDateTime;
import java.util.Collection;
import java.util.Collections;

/**
 * A {@link WindowAssigner} that assigns elements to time windows based on trading market sessions.
 * Windows are determined by market open and close times in the specified timezone.
 *
 * <p>For example, to window NYSE trading data into daily sessions (9:30 AM - 4:00 PM ET):
 *
 * <pre>{@code
 * DataStream<TradeEvent> trades = ...;
 * KeyedStream<TradeEvent, String> keyed = trades.keyBy(...);
 * WindowedStream<TradeEvent, String, TimeWindow> windowed =
 *   keyed.window(PricingSessionWindow.forMarket(
 *     "NYSE",
 *     ZoneId.of("America/New_York"),
 *     LocalTime.of(9, 30),
 *     LocalTime.of(16, 0)));
 * }</pre>
 *
 * <p>This implementation handles market sessions that may span date boundaries (e.g., futures
 * markets that trade overnight).
 */
@PublicEvolving
public class PricingSessionWindow extends MergingWindowAssigner<Object, TimeWindow> {
    private static final long serialVersionUID = 1L;

    private final String marketId;
    private final ZoneId timezone;
    private final LocalTime sessionOpen;
    private final LocalTime sessionClose;

    protected PricingSessionWindow(
            String marketId, ZoneId timezone, LocalTime sessionOpen, LocalTime sessionClose) {
        if (marketId == null || marketId.isEmpty()) {
            throw new IllegalArgumentException("Market ID must not be null or empty");
        }
        if (timezone == null) {
            throw new IllegalArgumentException("Timezone must not be null");
        }
        if (sessionOpen == null || sessionClose == null) {
            throw new IllegalArgumentException(
                    "Session open and close times must not be null");
        }

        this.marketId = marketId;
        this.timezone = timezone;
        this.sessionOpen = sessionOpen;
        this.sessionClose = sessionClose;
    }

    @Override
    public Collection<TimeWindow> assignWindows(
            Object element, long timestamp, WindowAssignerContext context) {
        // Convert the timestamp to the market's timezone
        ZonedDateTime eventTime = ZonedDateTime.ofInstant(
                java.time.Instant.ofEpochMilli(timestamp), timezone);

        // Get the session window for this timestamp
        TimeWindow window = getSessionWindow(eventTime);
        return Collections.singletonList(window);
    }

    /**
     * Determines the trading session window for a given timestamp.
     *
     * <p>If the timestamp falls within the session hours, returns a window from that day's open
     * to close. If the timestamp is outside session hours, returns a window for the next session.
     *
     * @param eventTime The event time in the market's timezone
     * @return A TimeWindow representing the trading session
     */
    private TimeWindow getSessionWindow(ZonedDateTime eventTime) {
        LocalTime eventLocalTime = eventTime.toLocalTime();
        java.time.LocalDate eventDate = eventTime.toLocalDate();

        // Determine if event time is within session hours
        boolean withinSession =
                !eventLocalTime.isBefore(sessionOpen)
                        && eventLocalTime.isBefore(sessionClose);

        java.time.LocalDate sessionDate;
        if (withinSession) {
            // Event is within the session, use current date
            sessionDate = eventDate;
        } else if (eventLocalTime.isBefore(sessionOpen)) {
            // Event is before session opens, use current date (it's tonight's session)
            sessionDate = eventDate;
        } else {
            // Event is after session closes, belongs to next day's session
            sessionDate = eventDate.plusDays(1);
        }

        // Create the session window for this date
        ZonedDateTime sessionOpenTime =
                ZonedDateTime.of(sessionDate, sessionOpen, timezone);
        ZonedDateTime sessionCloseTime =
                ZonedDateTime.of(sessionDate, sessionClose, timezone);

        // Handle overnight sessions (close time before open time)
        if (sessionClose.isBefore(sessionOpen)) {
            // If close time is on the next day
            if (eventLocalTime.isBefore(sessionClose)) {
                // Event is in the early morning part of an overnight session
                sessionOpenTime = sessionOpenTime.minusDays(1);
            }
            sessionCloseTime = sessionCloseTime.plusDays(1);
        }

        long windowStart = sessionOpenTime.toInstant().toEpochMilli();
        long windowEnd = sessionCloseTime.toInstant().toEpochMilli();

        return new TimeWindow(windowStart, windowEnd);
    }

