    public Trigger<Object, TimeWindow> getDefaultTrigger() {
        return EventTimeTrigger.create();
    }

    @Override
    public TypeSerializer<TimeWindow> getWindowSerializer(ExecutionConfig executionConfig) {
        return new TimeWindow.Serializer();
    }

    @Override
    public boolean isEventTime() {
        return true;
    }

    @Override
    public void mergeWindows(Collection<TimeWindow> windows, MergeCallback<TimeWindow> c) {
        TimeWindow.mergeWindows(windows, c);
    }

    @Override
    public String toString() {
        return String.format(
                "PricingSessionWindow(%s, %s, %s-%s)",
                marketId, timezone, sessionOpen, sessionClose);
    }

    /**
     * Creates a new {@code PricingSessionWindow} that assigns elements to windows based on trading
     * session times.
     *
     * @param marketId The market identifier (e.g., "NYSE", "LSE")
     * @param timezone The timezone in which the session times are defined
     * @param sessionOpen The local time when the session opens (e.g., 09:30)
     * @param sessionClose The local time when the session closes (e.g., 16:00)
     * @return A new PricingSessionWindow assigner
     */
    public static PricingSessionWindow forMarket(
            String marketId, ZoneId timezone, LocalTime sessionOpen, LocalTime sessionClose) {
        return new PricingSessionWindow(marketId, timezone, sessionOpen, sessionClose);
    }

    /**
     * Creates a new {@code PricingSessionWindow} with dynamic market extraction.
     *
     * @param <T> The type of elements
     * @param extractor The extractor to use to extract the market ID from input elements
     * @param timezone The timezone in which the session times are defined
     * @param sessionOpen The local time when the session opens (e.g., 09:30)
     * @param sessionClose The local time when the session closes (e.g., 16:00)
     * @return A new DynamicPricingSessionWindow assigner
     */
    @PublicEvolving
    public static <T> DynamicPricingSessionWindow<T> withDynamicMarket(
            TradingSessionExtractor<T> extractor,
            ZoneId timezone,
            LocalTime sessionOpen,
            LocalTime sessionClose) {
        return new DynamicPricingSessionWindow<>(extractor, timezone, sessionOpen, sessionClose);
    }
}

