    44→ *   keyed.window(PricingSessionWindow.forMarket(
    45→ *     "NYSE",
    46→ *     ZoneId.of("America/New_York"),
    47→ *     LocalTime.of(9, 30),
    48→ *     LocalTime.of(16, 0)));
    49→ * }</pre>
    50→ *
    51→ * <p>This implementation handles market sessions that may span date boundaries (e.g., futures
    52→ * markets that trade overnight).
    53→ */
    54→@PublicEvolving
    55→public class PricingSessionWindow extends MergingWindowAssigner<Object, TimeWindow> {
    56→    private static final long serialVersionUID = 1L;
    57→
    58→    private final String marketId;
    59→    private final ZoneId timezone;
    60→    private final LocalTime sessionOpen;
    61→    private final LocalTime sessionClose;
    62→
    63→    protected PricingSessionWindow(
    64→            String marketId, ZoneId timezone, LocalTime sessionOpen, LocalTime sessionClose) {
    65→        if (marketId == null || marketId.isEmpty()) {
    66→            throw new IllegalArgumentException("Market ID must not be null or empty");
    67→        }
    68→        if (timezone == null) {
    69→            throw new IllegalArgumentException("Timezone must not be null");
    70→        }
    71→        if (sessionOpen == null || sessionClose == null) {
    72→            throw new IllegalArgumentException(
    73→                    "Session open and close times must not be null");
    74→        }
    75→
    76→        this.marketId = marketId;
    77→        this.timezone = timezone;
    78→        this.sessionOpen = sessionOpen;
    79→        this.sessionClose = sessionClose;
    80→    }
    81→
    82→    @Override
    83→    public Collection<TimeWindow> assignWindows(
    84→            Object element, long timestamp, WindowAssignerContext context) {
    85→        // Convert the timestamp to the market's timezone
    86→        ZonedDateTime eventTime = ZonedDateTime.ofInstant(
    87→                java.time.Instant.ofEpochMilli(timestamp), timezone);
    88→
    89→        // Get the session window for this timestamp
    90→        TimeWindow window = getSessionWindow(eventTime);
    91→        return Collections.singletonList(window);
    92→    }
    93→
    94→    /**
    95→     * Determines the trading session window for a given timestamp.
    96→     *
    97→     * <p>If the timestamp falls within the session hours, returns a window from that day's open
    98→     * to close. If the timestamp is outside session hours, returns a window for the next session.
    99→     *
   100→     * @param eventTime The event time in the market's timezone
   101→     * @return A TimeWindow representing the trading session
   102→     */
   103→    private TimeWindow getSessionWindow(ZonedDateTime eventTime) {
   104→        LocalTime eventLocalTime = eventTime.toLocalTime();
   105→        java.time.LocalDate eventDate = eventTime.toLocalDate();
   106→
   107→        // Determine if event time is within session hours
   108→        boolean withinSession =
   109→                !eventLocalTime.isBefore(sessionOpen)
   110→                        && eventLocalTime.isBefore(sessionClose);
   111→
   112→        java.time.LocalDate sessionDate;
   113→        if (withinSession) {
   114→            // Event is within the session, use current date
   115→            sessionDate = eventDate;
   116→        } else if (eventLocalTime.isBefore(sessionOpen)) {
   117→            // Event is before session opens, use current date (it's tonight's session)
   118→            sessionDate = eventDate;
   119→        } else {
   120→            // Event is after session closes, belongs to next day's session
   121→            sessionDate = eventDate.plusDays(1);
   122→        }
   123→
   124→        // Create the session window for this date
   125→        ZonedDateTime sessionOpenTime =
   126→                ZonedDateTime.of(sessionDate, sessionOpen, timezone);
   127→        ZonedDateTime sessionCloseTime =
   128→                ZonedDateTime.of(sessionDate, sessionClose, timezone);
   129→
   130→        // Handle overnight sessions (close time before open time)
   131→        if (sessionClose.isBefore(sessionOpen)) {
   132→            // If close time is on the next day
   133→            if (eventLocalTime.isBefore(sessionClose)) {
   134→                // Event is in the early morning part of an overnight session
   135→                sessionOpenTime = sessionOpenTime.minusDays(1);
   136→            }
   137→            sessionCloseTime = sessionCloseTime.plusDays(1);
   138→        }
   139→
   140→        long windowStart = sessionOpenTime.toInstant().toEpochMilli();
   141→        long windowEnd = sessionCloseTime.toInstant().toEpochMilli();
   142→
