   147→    public Trigger<Object, TimeWindow> getDefaultTrigger() {
   148→        return EventTimeTrigger.create();
   149→    }
   150→
   151→    @Override
   152→    public TypeSerializer<TimeWindow> getWindowSerializer(ExecutionConfig executionConfig) {
   153→        return new TimeWindow.Serializer();
   154→    }
   155→
   156→    @Override
   157→    public boolean isEventTime() {
   158→        return true;
   159→    }
   160→
   161→    @Override
   162→    public void mergeWindows(Collection<TimeWindow> windows, MergeCallback<TimeWindow> c) {
   163→        TimeWindow.mergeWindows(windows, c);
   164→    }
   165→
   166→    @Override
   167→    public String toString() {
   168→        return String.format(
   169→                "PricingSessionWindow(%s, %s, %s-%s)",
   170→                marketId, timezone, sessionOpen, sessionClose);
   171→    }
   172→
