   174→     * Creates a new {@code PricingSessionWindow} that assigns elements to windows based on trading
   175→     * session times.
   176→     *
   177→     * @param marketId The market identifier (e.g., "NYSE", "LSE")
   178→     * @param timezone The timezone in which the session times are defined
   179→     * @param sessionOpen The local time when the session opens (e.g., 09:30)
   180→     * @param sessionClose The local time when the session closes (e.g., 16:00)
   181→     * @return A new PricingSessionWindow assigner
   182→     */
   183→    public static PricingSessionWindow forMarket(
   184→            String marketId, ZoneId timezone, LocalTime sessionOpen, LocalTime sessionClose) {
   185→        return new PricingSessionWindow(marketId, timezone, sessionOpen, sessionClose);
   186→    }
   187→
   188→    /**
   189→     * Creates a new {@code PricingSessionWindow} with dynamic market extraction.
   190→     *
   191→     * @param <T> The type of elements
   192→     * @param extractor The extractor to use to extract the market ID from input elements
   193→     * @param timezone The timezone in which the session times are defined
   194→     * @param sessionOpen The local time when the session opens (e.g., 09:30)
   195→     * @param sessionClose The local time when the session closes (e.g., 16:00)
   196→     * @return A new DynamicPricingSessionWindow assigner
   197→     */
   198→    @PublicEvolving
   199→    public static <T> DynamicPricingSessionWindow<T> withDynamicMarket(
   200→            TradingSessionExtractor<T> extractor,
   201→            ZoneId timezone,
   202→            LocalTime sessionOpen,
   203→            LocalTime sessionClose) {
   204→        return new DynamicPricingSessionWindow<>(extractor, timezone, sessionOpen, sessionClose);
   205→    }
   206→}
