 * A {@link WindowAssigner} that windows elements into sessions based on trading market sessions
 * with dynamically extracted market IDs. Windows cannot overlap.
 *
 * <p>For example, to window multi-market trading data with dynamic market extraction:
 *
 * <pre>{@code
 * DataStream<TradeEvent> trades = ...;
 * KeyedStream<TradeEvent, String> keyed = trades.keyBy(...);
 * WindowedStream<TradeEvent, String, TimeWindow> windowed =
 *   keyed.window(PricingSessionWindow.withDynamicMarket(
 *     TradeEvent::getMarket,
 *     ZoneId.of("America/New_York"),
 *     LocalTime.of(9, 30),
 *     LocalTime.of(16, 0)));
 * }</pre>
 *
 * @param <T> The type of the input elements
 */
@PublicEvolving
public class DynamicPricingSessionWindow<T> extends MergingWindowAssigner<T, TimeWindow> {
    private static final long serialVersionUID = 1L;

    private final TradingSessionExtractor<T> extractor;
    private final ZoneId timezone;
    private final LocalTime sessionOpen;
    private final LocalTime sessionClose;

    protected DynamicPricingSessionWindow(
            TradingSessionExtractor<T> extractor,
            ZoneId timezone,
            LocalTime sessionOpen,
            LocalTime sessionClose) {
        if (extractor == null) {
            throw new IllegalArgumentException("TradingSessionExtractor must not be null");
        }
        if (timezone == null) {
            throw new IllegalArgumentException("Timezone must not be null");
        }
        if (sessionOpen == null || sessionClose == null) {
            throw new IllegalArgumentException(
                    "Session open and close times must not be null");
        }

        this.extractor = extractor;
        this.timezone = timezone;
        this.sessionOpen = sessionOpen;
        this.sessionClose = sessionClose;
    }

    @Override
    public Collection<TimeWindow> assignWindows(
            T element, long timestamp, WindowAssignerContext context) {
        // Extract market ID from element (not used in window calculation, but available for validation)
        String marketId = extractor.extractMarketId(element);
        if (marketId == null || marketId.isEmpty()) {
            throw new IllegalArgumentException("Market ID extracted from element must not be null or empty");
        }

        // Convert the timestamp to the market's timezone
        ZonedDateTime eventTime = ZonedDateTime.ofInstant(
                java.time.Instant.ofEpochMilli(timestamp), timezone);

        // Get the session window for this timestamp
        TimeWindow window = getSessionWindow(eventTime);
        return Collections.singletonList(window);
    }

